import{_ as t,c as a,o,a5 as i}from"./chunks/framework.CgT1UzWm.js";const b=JSON.parse('{"title":"About This Website","titleTemplate":"NpgsqlRest","description":"On AI tools, the people behind NpgsqlRest, and how this documentation was built.","frontmatter":{"layout":"doc","outline":false,"title":"About This Website","titleTemplate":"NpgsqlRest","description":"On AI tools, the people behind NpgsqlRest, and how this documentation was built."},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),s={name:"about.md"};function n(r,e,h,l,u,d){return o(),a("div",null,e[0]||(e[0]=[i('<h1 id="about-this-website" tabindex="-1">About This Website <a class="header-anchor" href="#about-this-website" aria-label="Permalink to &quot;About This Website&quot;">​</a></h1><p>This website was built and is maintained with substantial help from AI tools — primarily <a href="https://claude.ai" target="_blank" rel="noreferrer">Claude</a>. Most pages carry a &quot;Written with Claude&quot; badge at the top to make this explicit. A small number of blog posts were written by hand and carry a &quot;Human Written&quot; badge instead. The badges link here.</p><h2 id="on-the-ai-question" tabindex="-1">On the AI Question <a class="header-anchor" href="#on-the-ai-question" aria-label="Permalink to &quot;On the AI Question&quot;">​</a></h2><p>As you may notice, this page and pretty much the entire website were obviously created with the help of AI. I wonder how you could tell? Was it a big &quot;Written With Claude&quot; badge on every page? I moved it to the top now (with the help of AI of course) to make it even more obvious.</p><p>There are a few blog posts that were written by me manually, the old-fashioned way, I hope there will be more in the future, and those have a similar &quot;Human Written&quot; badge.</p><p>This project (not the website), on the other hand, is a very, very different story. It took me more than two years of painstaking and unpaid work in my own free time. A story that, hopefully, I will tell someday.</p><p>But meanwhile, what would you like me to do? To create a complex documentation website with a bunch of highly technical articles with the help of AI and fake it, to give you an illusion that I also did that manually? Like half of the internet is doing at this point? How does that make any sense? Is that even fair to you?</p><p>Or maybe to create this website manually, the old-fashioned way, just for you? While working a paid job for a salary, most of you wouldn&#39;t even get up in the morning. Would you like me to sing you a song while we&#39;re at it? For your personal entertainment?</p><p>Seriously, get a grip.</p><p>Do you find this information less valuable because of the way this website was created? I give my best to keep the information as accurate as possible, and I think it is very accurate at this point. If you find some mistakes, inaccuracies, or problems, there is a comment section at the bottom of every page, which I also made with the help of AI. And I would very much appreciate it if you leave your feedback there.</p><p>Look, I&#39;m just a guy who likes SQL, that&#39;s all.</p><p>If you don&#39;t approve of how this website was constructed and the use of AI tools, I suggest closing this page and never ever coming back. And good riddance. I would ban your access if I knew how. Thank you for your attention to this matter.</p><h2 id="about-the-author" tabindex="-1">About the Author <a class="header-anchor" href="#about-the-author" aria-label="Permalink to &quot;About the Author&quot;">​</a></h2><p>NpgsqlRest is built and maintained by <a href="https://www.linkedin.com/in/vb-software/" target="_blank" rel="noreferrer">Vedran Bilopavlović</a>. The project itself — the C# library, parser, codegen, and runtime — is hand-written, tested with 1800+ integration tests, and battle-tested in production. The documentation website you&#39;re reading right now is the AI-assisted part.</p><h2 id="feedback" tabindex="-1">Feedback <a class="header-anchor" href="#feedback" aria-label="Permalink to &quot;Feedback&quot;">​</a></h2><p>Comments are open at the bottom of every page. Bug reports and feature requests live on <a href="https://github.com/NpgsqlRest/NpgsqlRest/issues" target="_blank" rel="noreferrer">GitHub</a>.</p>',16)]))}const c=t(s,[["render",n]]);export{b as __pageData,c as default};
